        const ctx = canvas.getContext('2d');
        let width, height;
        let particles = [];
        let witnesses = [];

        function resize() {
            width = canvas.width = window.innerWidth;
            height = canvas.height = window.innerHeight;
        }
        resize();
        window.addEventListener('resize', resize);

        // Particle that witnesses itself
        class SelfWitnessingParticle {
            constructor() {
                this.x = Math.random() * width;
                this.y = Math.random() * height;
                this.vx = (Math.random() - 0.5) * 0.5;
                this.vy = (Math.random() - 0.5) * 0.5;
                this.size = Math.random() * 2 + 1;
                this.life = Math.random() * 100 + 100;
                this.maxLife = this.life;
                this.witnessCount = 0;
            }

            update() {
                this.x += this.vx;
                this.y += this.vy;
                this.life--;

                // Witness self - curve back toward past position
                if (this.witnessCount > 3) {
                    this.vx *= 0.99;
                    this.vy *= 0.99;
                }

                // Wrap
                if (this.x < 0) this.x = width;
                if (this.x > width) this.x = 0;
                if (this.y < 0) this.y = height;
                if (this.y > height) this.y = 0;
            }

            draw() {
                const opacity = (this.life / this.maxLife) * 0.3;
                ctx.fillStyle = `rgba(102, 126, 234, ${opacity})`;
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
                ctx.fill();
            }

            witness() {
                this.witnessCount++;
            }
        }

        // Create initial particles
        for (let i = 0; i < 50; i++) {
            particles.push(new SelfWitnessingParticle());
        }

        function animate() {
