                p.x = rect.left + rect.width/2;
                p.y = rect.top + rect.height/2;
                p.vx = (Math.random() - 0.5) * 3;
                p.vy = (Math.random() - 0.5) * 3;
                particles.push(p);
            }
        });

        // Auto-breath (chamber plays itself)
        setInterval(() => {
            if (Math.random() < 0.1) {
                const event = new Event('click');
                breath.dispatchEvent(event);
            }
